  window.financeProAddDistributionV15=function(){const center=S($('finDistCenterV15')?.value)||'FM', type=S($('finDistTypeV15')?.value)||'out', pid=S($('finDistProjectV15')?.value), qty=N($('finDistQtyV15')?.value); if(qty<=0)return alert('كمية التوزيع مطلوبة'); state.distribution.push({center,type,projectId:pid||null,projectName:pid?projectName(pid):'',orderNo:S($('finDistOrderV15')?.value),qty,note:S($('finDistNoteV15')?.value)}); ['finDistOrderV15','finDistQtyV15','finDistNoteV15'].forEach(id=>{if($(id))$(id).value='';}); renderDistribution();};
