  window.financeProSaveMovementV15=async function(btn){
    try{
      if(btn)btn.disabled=true;
      const c=client(); if(!c)throw new Error('الاتصال غير جاهز');
      const item=state.items.find(i=>String(i.id)===String($('finMoveItemV15')?.value)); if(!item)throw new Error('اختر المنتج');
      const qty=N($('finMoveQtyV15')?.value), type=S($('finMoveTypeV15')?.value)||'out';
      if(qty<=0)throw new Error('الكمية مطلوبة');
      const old=state.editMovementId?state.movements.find(m=>String(m.id)===String(state.editMovementId)):null;
      const same=old&&String(old.item_id)===String(item.id)?old:null;
      const oldItem=old&&!same?state.items.find(i=>String(i.id)===String(old.item_id)):null;
      const availableBeforeOld = same ? (computedItemQty(item)-movementComputedDelta(old)) : computedItemQty(item);
      if(movementOutTypes().includes(type)&&availableBeforeOld<qty)throw new Error('الكمية المتوفرة لا تكفي');
      const distTotal=state.distribution.reduce((s,d)=>s+N(d.qty),0);
      if(movementOutTypes().includes(type)&&state.distribution.length&&Math.abs(distTotal-qty)>.001)throw new Error('إجمالي التوزيع يجب أن يساوي كمية الحركة');
      const staff=S($('finMoveStaffV15')?.value);
      const meta={module:VERSION,staffId:staff,note:S($('finMoveNoteV15')?.value),distribution:state.distribution,stockEffect:'normal'};
      const mv={item_id:item.id,item_name:item.name,movement_type:type,quantity:qty,movement_date:S($('finMoveDateV15')?.value)||today(),receiver:staffName(staff),reason:{return:'مرتجع مخزون',consume:'مستهلك',waste:'مهدور',damaged:'تالف',scrap:'سكراب',out:'صرف مخزون'}[type]||'صرف مخزون',notes:'finance_pro_v15:'+JSON.stringify(meta),product_code:itemCode(item),barcode:itemCode(item),unit_cost:+itemUnitCost(item).toFixed(4)};
      const res=old?await c.from('inventory_movements').update(mv).eq('id',old.id):await c.from('inventory_movements').insert(mv);
      if(res.error)throw res.error;
      if(oldItem){
        const oldRawBefore=N(oldItem.quantity)-movementStockDelta(old);
        const oldUpd=await c.from('inventory_items').update({quantity:oldRawBefore}).eq('id',oldItem.id);
        if(oldUpd.error)throw oldUpd.error;
      }
      const oldMainDelta=same?movementStockDelta(old):0;
      const baseRaw=N(item.quantity)-oldMainDelta;
      const newRaw=baseRaw+(qty*moveSign(type));
      const upd=await c.from('inventory_items').update({quantity:newRaw}).eq('id',item.id);
      if(upd.error)throw upd.error;
      state.distribution=[]; state.editMovementId='';
      await loadAll(true); renderShell();
      if(typeof msg==='function')msg(old?'تم تعديل حركة المخزون وتحديث التقرير':'تم حفظ حركة المخزون');
    }catch(e){alert(e.message||String(e)); if(typeof msg==='function')msg(e.message||String(e),'err');}
    finally{if(btn)btn.disabled=false;}
  };
  function fillMovementEdit(m){if($('finMoveItemV15'))$('finMoveItemV15').value=m.item_id||''; if($('finMoveTypeV15'))$('finMoveTypeV15').value=S(m.movement_type)||'out'; if($('finMoveQtyV15'))$('finMoveQtyV15').value=N(m.quantity); if($('finMoveDateV15'))$('finMoveDateV15').value=movementDate(m)||today(); if($('finMoveNoteV15'))$('finMoveNoteV15').value=S((safeJson(m.notes)||{}).note||''); const btn=$('finMoveSaveBtnV15'); if(btn)btn.textContent='تحديث الحركة';}
